import{_ as a,o as l,c as i,ag as r}from"./chunks/framework.DvSl3FxN.js";const c=JSON.parse('{"title":"历史资料","description":"","frontmatter":{"title":"历史资料"},"headers":[],"relativePath":"novels/jin-gu-yao/behind-the-scenes/history.md","filePath":"novels/jin-gu-yao/behind-the-scenes/history.md","lastUpdated":1773897450000}'),o={name:"novels/jin-gu-yao/behind-the-scenes/history.md"};function e(d,t,h,n,s,u){return l(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="历史资料-—-平阳昭公主" tabindex="-1">历史资料 — 平阳昭公主 <a class="header-anchor" href="#历史资料-—-平阳昭公主" aria-label="Permalink to &quot;历史资料 — 平阳昭公主&quot;">​</a></h1><h2 id="一、正史记载" tabindex="-1">一、正史记载 <a class="header-anchor" href="#一、正史记载" aria-label="Permalink to &quot;一、正史记载&quot;">​</a></h2><h3 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h3><ul><li><strong>身份</strong>：唐高祖李渊第三女，嫡妻窦氏（窦皇后）所生</li><li><strong>名字</strong>：正史未记载真名（民间/影视常用&quot;李秀宁&quot;&quot;李三娘&quot;，均非正史）</li><li><strong>丈夫</strong>：柴绍（隋元德太子千牛备身出身，后为凌烟阁二十四功臣第十四位）</li><li><strong>儿子</strong>：柴哲威、柴令武</li><li><strong>谥号</strong>：昭（&quot;明德有功曰昭&quot;）</li><li><strong>下葬</strong>：武德六年（623年）二月，以军礼下葬，中国封建史上唯一</li></ul><h3 id="核心事件时间线" tabindex="-1">核心事件时间线 <a class="header-anchor" href="#核心事件时间线" aria-label="Permalink to &quot;核心事件时间线&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时间</th><th>事件</th></tr></thead><tbody><tr><td>大业十三年（617）五月</td><td>李渊决定起兵，密召柴绍夫妇</td></tr><tr><td>617年五月</td><td>柴绍赴太原，公主留长安自行安排</td></tr><tr><td>617年五月-八月</td><td>公主回鄠县李氏庄园，女扮男装自称&quot;李公子&quot;，散财赈民，招募数百人</td></tr><tr><td>617年六月-九月</td><td>收编何潘仁（手下数万人）、李仲文、向善志、丘师利等义军</td></tr><tr><td>617年间</td><td>连续攻占户县、周至、武功、始平等地</td></tr><tr><td>617年九月</td><td>李渊主力渡黄河入关中，公主已为其打下大片地盘</td></tr><tr><td>617年九月</td><td>柴绍带数百骑兵迎接公主</td></tr><tr><td>617年九月</td><td>公主挑选精兵一万余人，与李世民会师渭河北岸</td></tr><tr><td>617年十一月</td><td>夫妻各领一军（各自有幕府），共克长安</td></tr><tr><td>617年后</td><td>封&quot;平阳公主&quot;，因独有军功，赏赐异于他公主</td></tr><tr><td>617年后-623年</td><td>驻守娘子关（原名苇泽关），防守山西大本营</td></tr><tr><td>武德六年（623）二月</td><td>薨，以军礼下葬，谥&quot;昭&quot;</td></tr></tbody></table><h3 id="关键史料原文" tabindex="-1">关键史料原文 <a class="header-anchor" href="#关键史料原文" aria-label="Permalink to &quot;关键史料原文&quot;">​</a></h3><p><strong>《唐会要》记载：</strong></p><blockquote><p>&quot;高祖第三女平阳公主。义兵起，公主于鄠县庄，散家资招引山中亡命，得数百人。起兵以应高祖。略地至盩厔武功始平，皆下之。每申明法令，禁兵无得侵掠，故远近奔赴甚众，得兵七万人。公主间使以闻，使者至，高祖大悦。及义军渡河。公主引精兵万馀，与太宗会於渭北，与其驸马柴绍，各置幕府。营中号为娘子军。京城平，封为平阳公主。以独有军功，每赏赐异於他主。及薨，追谥曰昭。&quot;</p></blockquote><p><strong>李渊反驳礼官（关于军礼下葬）：</strong></p><blockquote><p>&quot;鼓吹，军乐也。往者公主于司竹举兵以应义旗，亲执金鼓，有克定之勋。周之文母，列于十乱；公主功参佐命，非常妇人之所匹也。何得无鼓吹！&quot;</p></blockquote><p><strong>《新唐书》评价：</strong></p><blockquote><p>&quot;乃申法誓众，禁剽夺，远近咸附，勒兵七万，威振关中。&quot;</p></blockquote><h3 id="柴绍离别时的对话" tabindex="-1">柴绍离别时的对话 <a class="header-anchor" href="#柴绍离别时的对话" aria-label="Permalink to &quot;柴绍离别时的对话&quot;">​</a></h3><p>柴绍：&quot;你的父亲将要起兵扫平乱世，我打算前去迎接他的义旗，一起离开不可行，我独自走后又害怕你有危险，到底应该怎么办呢？&quot; 公主：&quot;你应该赶紧离开，我是一个妇人，遇到危险容易躲藏起来，到那时自己会有办法的。&quot;</p><hr><h2 id="二、重要人物" tabindex="-1">二、重要人物 <a class="header-anchor" href="#二、重要人物" aria-label="Permalink to &quot;二、重要人物&quot;">​</a></h2><h3 id="柴绍" tabindex="-1">柴绍 <a class="header-anchor" href="#柴绍" aria-label="Permalink to &quot;柴绍&quot;">​</a></h3><ul><li>出身将门，自幼&quot;矫捷有勇力，以抑强扶弱&quot;</li><li>曾为隋元德太子千牛备身</li><li>李渊起兵后，走小道赴太原，途中与李建成、李元吉汇合</li><li>授右领军大都督府长史，兼领马军总管</li><li>攻长安时与公主平级，各领一军，各有幕府</li><li>后随李世民征战：平薛举、破宋金刚、败王世充、擒窦建德</li><li>封霍国公，凌烟阁二十四功臣第十四位</li><li><strong>有趣轶事</strong>：被吐谷浑围困山谷时，临危不惧，安然而坐，让人弹琵琶、二美女翩翩对舞，吐谷浑兵放下弓矢观看，趁机派精骑绕后突袭，大败敌军</li><li>贞观十二年（638年）病逝</li></ul><h3 id="何潘仁" tabindex="-1">何潘仁 <a class="header-anchor" href="#何潘仁" aria-label="Permalink to &quot;何潘仁&quot;">​</a></h3><ul><li>胡商（西域商人出身），手下有数万人</li><li>公主派家僮马三宝前去游说，何潘仁&quot;居然甘愿做平阳公主的手下&quot;</li><li>史书未详细记载马三宝用了什么手段 — <strong>此处想象空间极大</strong></li></ul><h3 id="马三宝" tabindex="-1">马三宝 <a class="header-anchor" href="#马三宝" aria-label="Permalink to &quot;马三宝&quot;">​</a></h3><ul><li>公主家僮（家仆）</li><li>被派去游说何潘仁归降 — 一个家仆说服了一个拥兵数万的胡商，这本身就是传奇</li><li>后续事迹不详</li></ul><h3 id="李世民" tabindex="-1">李世民 <a class="header-anchor" href="#李世民" aria-label="Permalink to &quot;李世民&quot;">​</a></h3><ul><li>公主的弟弟（一说兄弟，公主排行第三但具体与世民年龄关系不确定）</li><li>渡河后与公主会师渭北，共克长安</li></ul><h3 id="李渊" tabindex="-1">李渊 <a class="header-anchor" href="#李渊" aria-label="Permalink to &quot;李渊&quot;">​</a></h3><ul><li>公主之父</li><li>对公主军功极为认可，力排众议以军礼下葬</li><li>评价公主&quot;功参佐命，非常妇人之所匹也&quot;</li></ul><hr><h2 id="三、地理信息" tabindex="-1">三、地理信息 <a class="header-anchor" href="#三、地理信息" aria-label="Permalink to &quot;三、地理信息&quot;">​</a></h2><h3 id="鄠县-今陕西鄠邑区" tabindex="-1">鄠县（今陕西鄠邑区） <a class="header-anchor" href="#鄠县-今陕西鄠邑区" aria-label="Permalink to &quot;鄠县（今陕西鄠邑区）&quot;">​</a></h3><ul><li>公主的起兵之地，李氏庄园所在</li><li>位于长安西南约50公里</li></ul><h3 id="关中地区攻占路线" tabindex="-1">关中地区攻占路线 <a class="header-anchor" href="#关中地区攻占路线" aria-label="Permalink to &quot;关中地区攻占路线&quot;">​</a></h3><ul><li>户县 → 周至 → 武功 → 始平</li><li>由西向东推进，为李渊入关中扫清障碍</li></ul><h3 id="娘子关-原名苇泽关" tabindex="-1">娘子关（原名苇泽关） <a class="header-anchor" href="#娘子关-原名苇泽关" aria-label="Permalink to &quot;娘子关（原名苇泽关）&quot;">​</a></h3><ul><li>位于今山西省平定县东北</li><li>太行山上，出入山西的咽喉要道</li><li>因公主率&quot;娘子军&quot;驻守而改名</li><li>关城傍山近水，南侧群峰逶迤，北侧百丈悬崖下绵河湍急</li><li><strong>注意</strong>：有学者考证公主可能并未实际驻守此地，&quot;娘子关&quot;之名可能是后人附会。但作为小说可以合理使用。</li></ul><h3 id="渭河" tabindex="-1">渭河 <a class="header-anchor" href="#渭河" aria-label="Permalink to &quot;渭河&quot;">​</a></h3><ul><li>公主与李世民会师之地（渭河北岸）</li></ul><hr><h2 id="四、历史留白与想象空间" tabindex="-1">四、历史留白与想象空间 <a class="header-anchor" href="#四、历史留白与想象空间" aria-label="Permalink to &quot;四、历史留白与想象空间&quot;">​</a></h2><p>这些是正史没有记载、但对小说创作极有价值的空白：</p><ol><li><strong>公主的真名</strong> — 正史无载，我们可以赋予她一个名字</li><li><strong>柴绍离开后的心理</strong> — 丈夫走了，她独自面对隋朝追捕，那一夜她在想什么？</li><li><strong>如何说服何潘仁</strong> — 马三宝到底用了什么手段？一个家仆如何让拥兵数万的胡商臣服于一个贵族女性？</li><li><strong>军中日常</strong> — 她如何管理七万人？如何建立军纪？如何处理士兵对女性统帅的质疑？</li><li><strong>两个儿子</strong> — 何时出生？在她征战期间如何照顾？是否带在军中？</li><li><strong>与柴绍重逢</strong> — 分别数月后，各自已是统帅，重逢时是什么场景？</li><li><strong>617年至623年的六年</strong> — 攻克长安后到去世前的六年，史书几乎空白。她在做什么？为什么突然去世？</li><li><strong>死因</strong> — 完全不详。病死？战死？难产？政治原因？想象空间巨大</li><li><strong>与李世民的关系</strong> — 姐弟之间的互动，会师时的场景</li><li><strong>米汤退敌兵</strong> — 野史轶事，可以作为素材</li></ol><hr><h2 id="五、时代背景" tabindex="-1">五、时代背景 <a class="header-anchor" href="#五、时代背景" aria-label="Permalink to &quot;五、时代背景&quot;">​</a></h2><h3 id="隋末乱世-大业末年-约614-618年" tabindex="-1">隋末乱世（大业末年，约614-618年） <a class="header-anchor" href="#隋末乱世-大业末年-约614-618年" aria-label="Permalink to &quot;隋末乱世（大业末年，约614-618年）&quot;">​</a></h3><ul><li>隋炀帝三征高句丽，国力耗竭</li><li>全国农民起义此起彼伏</li><li>三大主力：李密（瓦岗军）、窦建德、杜伏威</li><li>地方官吏纷纷割据称王</li><li>社会秩序崩溃，流民遍地</li><li>关中地区相对稳定但暗流涌动</li></ul><h3 id="李渊起兵" tabindex="-1">李渊起兵 <a class="header-anchor" href="#李渊起兵" aria-label="Permalink to &quot;李渊起兵&quot;">​</a></h3><ul><li>大业十三年（617年）五月，太原起兵</li><li>七月，统甲士三万晋阳誓师</li><li>九月，渡黄河入关中</li><li>十一月，攻克长安</li><li>武德元年（618年）五月，称帝建唐</li></ul><hr><h2 id="六、已有影视改编" tabindex="-1">六、已有影视改编 <a class="header-anchor" href="#六、已有影视改编" aria-label="Permalink to &quot;六、已有影视改编&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>作品</th><th>演员</th><th>角色名</th></tr></thead><tbody><tr><td>1993</td><td>《唐太宗李世民》</td><td>张蓓</td><td>李三娘</td></tr><tr><td>1996</td><td>《隋唐演义》</td><td>秦雯雯</td><td>李凤阳</td></tr><tr><td>2004</td><td>《大唐双龙传》</td><td>杨怡</td><td>李秀宁</td></tr><tr><td>2011</td><td>《大唐双龙传之长生诀》</td><td>应采儿</td><td>李秀宁</td></tr><tr><td>2017</td><td>《天下长安》</td><td>姚星彤</td><td>李木兰</td></tr></tbody></table><p><strong>启示</strong>：现有影视多为配角，且多走武侠/言情路线。我们的小说可以走更深刻的历史叙事路线，差异化明显。</p>',51)])])}const b=a(o,[["render",e]]);export{c as __pageData,b as default};
